INSERT INTO testimonials (name, position, company, content, rating, image, active) VALUES 
('Батбаатар', 'Гүйцэтгэх захирал', 'Монгол Банк', 'МонКонстракшн компанид баярлалаа. Төслийн хугацаанд чанартай гүйцэтгэсэн. Үргэлж хамтран ажиллахад бэлэн байна.', 5, '/api/placeholder/100/100', true),
('Сарангэрэл', 'Төслийн менежер', 'Наран ХХК', 'Маш сайн туршлага. Мэргэжилтнүүд нь өндөр чадвартай, төслийн бүх шатанд идэвхтэй оролцож байлаа.', 5, '/api/placeholder/100/100', true),
('Ганбаатар', 'Хөрөнгө оруулагч', 'Техно Инвест', 'Барилгын чанар, аюулгүй байдалд тулгамдсан. Дараагийн төслөө мөн МонКонстракшнд хүргэхээр шийдлээ.', 4, '/api/placeholder/100/100', true),
('Нарантуяа', 'Сургуулийн захирал', 'Их Сургууль', 'Сургуулийн барилгыг зааварчилгааны дагуу бүрэн гүйцэтгэлээр хүлээлгэв. Сурагчид, багш нар сэтгэл хангалуун байна.', 5, '/api/placeholder/100/100', true),
('Тэмүүлэн', 'CEO', 'Дижитал Солюшн', 'Оффисын барилгыг нээснээс хойш ажиллах орчин маш сайнаар болсон. Ажилчид маань баярлаж байна.', 5, '/api/placeholder/100/100', true);
