INSERT INTO faqs (category, question, answer, order_num, active) VALUES 
('Ерөнхий', 'Таны компани хэдэн жилийн туршлагатай вэ?', 'Манай компани 2014 оноос эхлэн 10 жилийн туршлагатай барилгын салбарт тэргүүлэгч байр суурь эзэлж байна.', 1, true),
('Ерөнхий', 'Ямар төрлийн барилга барих чадвартай вэ?', 'Бид орон сууц, оффис, үйлдвэрийн барилга, нийтийн байр, хувийн байр зэрэг бүх төрлийн барилгын ажил хийдэг.', 2, true),
('Үнэ өртөг', 'Барилгын үнэ ханш ямар байдаг вэ?', 'Үнэ өртөг нь төслийн хэмжээ, хэрэглэх материал, дизайн, байршил зэргээс хамаарч өөр өөр байна. Дэлгэрэнгүй мэдээллийг тооцоо хийлгэхээр болно.', 3, true),
('Үнэ өртөг', 'Төлбөрийн нөхцөл ямар вэ?', 'Бид урьдчилж 30%, дараа нь ажлын явцад 40%, дууссаны дараа 30% гэсэн төлбөрийн нөхцөл санал болгодог.', 4, true),
('Хугацаа', 'Дундаж барилгын хугацаа хэд вэ?', 'Орон сууцны комплекс 12-18 сар, оффисын барилга 8-12 сар, хувийн байр 6-8 сар орчим хугацаанд дуусдаг.', 5, true),
('Хугацаа', 'Төслийг эхлэхэд ямар баримт бичиг хэрэгтэй вэ?', 'Газрын эзэмшлийн баримт, архитектурын зураг, төсвийн тооцоо, зөвшөөрөл зэрэг баримт бичиг хэрэгтэй.', 6, true),
('Баталгаа', 'Барилгын баталгаа хэдэн жил вэ?', 'Бид бүх барилгадаа хуулийн заалтад нийцсэн баталгаатай үйлчилгээ үзүүлдэг. Орон сууцны барилгад 5 жил, бусад барилгад 2-3 жилийн баталгаатай.', 7, true),
('Баталгаа', 'Хэрэв асуудал гарвал яах вэ?', 'Бид 24/7 үйлчилгээний төвтэй, гарсан асуудлыг шуурхай шийддэг. Мөн баталгаатай үйлчилгээний гэрээтэй ажилладаг.', 8, true);
